import { HttpClient, HttpErrorResponse, HttpHeaders, HttpResponse, HttpResponseBase } from '@angular/common/http';
import { Component, OnInit } from '@angular/core';
import { FormArray, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { DomSanitizer, SafeResourceUrl } from '@angular/platform-browser';
import * as _ from 'lodash';
import { Observable, of, throwError } from 'rxjs';
import { catchError, map, startWith, timeout } from 'rxjs/operators';
import { HttpMethod, httpMethods } from './HttpMethod';
import { headerNameOptions, contentTypeOptions } from './options';

// type HeaderFormArray = FormArray & { controls: FormGroup[] };

class HeaderFormArray extends FormArray {
  controls!: FormGroup[];
}

@Component({
  selector: 'app-request',
  templateUrl: './request.component.html',
  styleUrls: ['./request.component.scss']
})
export class RestClientComponent implements OnInit {
  httpMethods = httpMethods;
  headerNameOptions = headerNameOptions;
  contentTypeOptions = contentTypeOptions;

  filteredHeaderNameOptions: Observable<string[]> = of();

  controls = {
    method: this.fb.control(httpMethods[0], Validators.required),
    url: this.fb.control('', Validators.required),
    body: this.fb.control(''),
    headers: this.fb.array([]) as HeaderFormArray
  };

  get contentTypeForm(): FormGroup {
    const forms = this.controls.headers.controls;
    let form = forms.find(it => it.controls.name.value.toLowerCase() === 'content-type');

    if (form === undefined) {
      form = this.addHeaderForm('Content-Type', '');
    }

    return form;
  }

  requestForm = new FormGroup(this.controls);

  requesting = false;
  requested = false;

  successful = false;

  response?: HttpResponseBase;
  responseBody?: string;
  responseContentType?: string;
  downloadUrl?: SafeResourceUrl;

  get shouldShowBodyTab(): boolean {
    const method = this.controls.method.value as HttpMethod;
    return method === 'POST' || method === 'PUT' || method === 'PATCH';
  }

  constructor(private fb: FormBuilder, private httpClient: HttpClient, private sanitizer: DomSanitizer) {}

  ngOnInit(): void {
    this.addHeaderForm();
  }

  addHeaderForm(name: string = '', value: string = ''): FormGroup {
    const form = this.fb.group({
      name,
      value
    });

    this.controls.headers.push(form);

    return form;
  }

  initFilteredHeaderNameOptions(headerForm: FormGroup) {
    this.filteredHeaderNameOptions = headerForm.controls.name.valueChanges.pipe(
      startWith(headerForm.controls.name.value),
      map(it => this.getHeaderNameOptions(it))
    );
  }

  private getHeaderNameOptions(value: string): string[] {
    const filterValue = value.toLowerCase();
    return this.headerNameOptions.filter(option => option.toLowerCase().includes(filterValue));
  }

  removeHeaderForm(index: number) {
    this.controls.headers.removeAt(index);
  }

  sendRequest() {
    try {
      this.requested = true;
      this.requesting = true;
      this.successful = false;

      this.response = undefined;
      this.responseBody = undefined;
      this.responseContentType = undefined;
      this.downloadUrl = undefined;

      const method = this.controls.method.value as HttpMethod;
      const url = this.controls.url.value as string;
      const body = (this.controls.body.value as string) || null;

      const inputHeaders = this.controls.headers.controls.map(it => {
        return {
          name: (it.controls.name.value as string).trim(),
          value: (it.controls.value.value as string).trim()
        };
      });

      const headers: { [name: string]: string[] } = _(inputHeaders)
        .filter(it => !_.isEmpty(it.name))
        .groupBy(it => it.name)
        .mapValues(header => header.map(it => it.value))
        .value();

      const options = {
        observe: 'response',
        responseType: 'blob',
        headers: new HttpHeaders(headers)
      } as const;

      let observe;

      if (method === 'GET') {
        observe = this.httpClient.get(url, options);
      } else if (method === 'HEAD') {
        observe = this.httpClient.head(url, options);
      } else if (method === 'DELETE') {
        observe = this.httpClient.delete(url, options);
      } else if (method === 'OPTIONS') {
        observe = this.httpClient.options(url, options);
      } else if (method === 'POST') {
        observe = this.httpClient.post(url, body, options);
      } else if (method === 'PUT') {
        observe = this.httpClient.put(url, body, options);
      } else if (method === 'PATCH') {
        observe = this.httpClient.patch(url, body, options);
      } else {
        throw new Error(`Unsupported HTTP method: ${method}`);
      }

      observe
        .pipe(timeout(5000), catchError(this.handleError))
        .subscribe((res: HttpResponse<Blob>) => {
          this.response = res;
          this.successful = true;

          const blob = res.body;

          if (blob === null) {
            this.responseBody = undefined;
          } else {
            this.responseContentType = blob.type;
            this.downloadUrl = this.sanitizer.bypassSecurityTrustResourceUrl(window.URL.createObjectURL(blob));
            new Response(blob).text().then(text => (this.responseBody = text));
          }
        })
        .add(() => (this.requesting = false));
    } catch (e) {
      this.requesting = false;
    }
  }

  private handleError(error: any) {
    if (error instanceof HttpErrorResponse) {
      this.response = error;

      if (error.error instanceof ErrorEvent) {
        console.error('An error occurred:', error.error.message);
      } else if (error.error instanceof Blob) {
        const blob = error.error;
        this.responseContentType = blob.type;
        this.downloadUrl = this.sanitizer.bypassSecurityTrustResourceUrl(window.URL.createObjectURL(blob));
        new Response(blob).text().then(text => (this.responseBody = text));
      } else {
        console.error(`Backend returned code ${error.status}, ` + `body was: ${error.error}`);
      }
    }

    return throwError('Something bad happened; please try again later.');
  }
}
